// The ensures of det_get is an *implication* (P ==> det_get_equal(r1, r2)).
// Outside the implication's antecedent, `r1@ == self_@[*k]` is not a fact,
// so the prior attempt's unconditional asserts failed. Wrap the derivation
// inside an `if` matching the antecedent: now both equalities are in scope
// and transitivity through the common term `self_@[*k]` lines the two
// ensures triggers up so z3 sees `r1@ == r2@`.
if r1@ == self_@[*k] && r1@.valid_physical_address()
    && r2@ == self_@[*k] && r2@.valid_physical_address()
{
    assert(r1@ == self_@[*k]);
    assert(r2@ == self_@[*k]);
    assert(r1@ == r2@);
    assert(r1@.valid_physical_address());
    assert(r2@.valid_physical_address());
}
